7. 
8. var builder = WebApplication.CreateBuilder(args);
9. 
10. // Add services to the container.
11. builder.Services.AddRazorComponents()
12.     .AddInteractiveServerComponents();
13. 
14. builder.Services.AddCascadingAuthenticationState();
15. builder.Services.AddScoped<IdentityRedirectManager>();
16. builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();
17. 
18. builder.Services.AddAuthentication(options =>
19.     {
20.         options.DefaultScheme = IdentityConstants.ApplicationScheme;
21.         options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
22.     })
23.     .AddIdentityCookies();
24. 
25. var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
26. builder.Services.AddDbContext<ApplicationDbContext>(options =>
27.     options.UseSqlite(connectionString));
28. builder.Services.AddDatabaseDeveloperPageExceptionFilter();
29. 
30. builder.Services.AddIdentityCore<ApplicationUser>(options =>
31.     {
32.         options.SignIn.RequireConfirmedAccount = true;
33.         options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
34.     })
35.     .AddEntityFrameworkStores<ApplicationDbContext>()
36.     .AddSignInManager()
37.     .AddDefaultTokenProviders();
38. 
39. builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
40. 
41. var app = builder.Build();
42. 
43. // Configure the HTTP request pipeline.
44. if (app.Environment.IsDevelopment())
45. {
46.     app.UseMigrationsEndPoint();
47. }
48. else
49. {
50.     app.UseExceptionHandler("/Error", createScopeForErrors: true);
51. }
52. app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
53. app.UseAntiforgery();
54. 
55. app.MapStaticAssets();
56. app.MapRazorComponents<App>()
57.     .AddInteractiveServerRenderMode();
58. 
59. // Add additional endpoints required by the Identity /Account Razor components.
60. app.MapAdditionalIdentityEndpoints();
61. 
62. app.Run();
63.

