using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using VetClinic.Data.Models;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceItem> InvoiceItems => Set<InvoiceItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>(e =>
        {
            e.HasIndex(o => o.LastName);
            e.HasIndex(o => o.Phone);
        });

        builder.Entity<Pet>(e =>
        {
            e.HasOne(p => p.Owner)
                .WithMany(o => o.Pets)
                .HasForeignKey(p => p.OwnerId)
                .OnDelete(DeleteBehavior.Restrict);
        });

        builder.Entity<Appointment>(e =>
        {
            e.HasOne(a => a.Pet)
                .WithMany(p => p.Appointments)
                .HasForeignKey(a => a.PetId)
                .OnDelete(DeleteBehavior.Restrict);
            e.HasIndex(a => a.StartTime);
            e.HasIndex(a => a.Status);
        });

        builder.Entity<TreatmentNote>(e =>
        {
            e.HasOne(t => t.Pet)
                .WithMany(p => p.TreatmentNotes)
                .HasForeignKey(t => t.PetId)
                .OnDelete(DeleteBehavior.Restrict);
            e.HasOne(t => t.Appointment)
                .WithMany()
                .HasForeignKey(t => t.AppointmentId)
                .OnDelete(DeleteBehavior.SetNull);
        });

        builder.Entity<Invoice>(e =>
        {
            e.HasOne(i => i.Pet)
                .WithMany(p => p.Invoices)
                .HasForeignKey(i => i.PetId)
                .OnDelete(DeleteBehavior.Restrict);
            e.HasOne(i => i.Appointment)
                .WithMany()
                .HasForeignKey(i => i.AppointmentId)
                .OnDelete(DeleteBehavior.SetNull);
            e.Ignore(i => i.TotalAmount);
            e.Ignore(i => i.AmountPaid);
            e.Ignore(i => i.BalanceDue);
        });

        builder.Entity<InvoiceItem>(e =>
        {
            e.HasOne(ii => ii.Invoice)
                .WithMany(i => i.Items)
                .HasForeignKey(ii => ii.InvoiceId)
                .OnDelete(DeleteBehavior.Cascade);
            e.Ignore(ii => ii.Amount);
            e.Property(ii => ii.UnitPrice).HasColumnType("decimal(18,2)");
        });

        builder.Entity<Payment>(e =>
        {
            e.HasOne(p => p.Invoice)
                .WithMany(i => i.Payments)
                .HasForeignKey(p => p.InvoiceId)
                .OnDelete(DeleteBehavior.Restrict);
            e.Property(p => p.Amount).HasColumnType("decimal(18,2)");
        });
    }
}

