using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    // ── Owners ──

    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var q = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.Trim().ToLower();
            q = q.Where(o => o.LastName.ToLower().Contains(search)
                          || o.FirstName.ToLower().Contains(search)
                          || o.Phone.Contains(search));
        }
        return await q.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task<Owner> SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0)
        {
            owner.CreatedAt = DateTime.UtcNow;
            db.Owners.Add(owner);
        }
        else
        {
            db.Owners.Update(owner);
        }
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task DeleteOwnerAsync(int id)
    {
        var owner = await db.Owners.FindAsync(id);
        if (owner is not null)
        {
            db.Owners.Remove(owner);
            await db.SaveChangesAsync();
        }
    }

    // ── Pets ──

    public async Task<List<Pet>> GetPetsAsync(string? search = null)
    {
        var q = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.Trim().ToLower();
            q = q.Where(p => p.Name.ToLower().Contains(search)
                          || p.Owner.LastName.ToLower().Contains(search));
        }
        return await q.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<Pet> SavePetAsync(Pet pet)
    {
        if (pet.Id == 0)
        {
            pet.CreatedAt = DateTime.UtcNow;
            db.Pets.Add(pet);
        }
        else
        {
            db.Pets.Update(pet);
        }
        await db.SaveChangesAsync();
        return pet;
    }

    // ── Treatment Notes ──

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        note.CreatedAt = DateTime.UtcNow;
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task<TreatmentNote> UpdateTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
        return note;
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime from, DateTime to)
    {
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= from && a.StartTime < to)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task<List<TimeSlot>> GetAvailableSlotsAsync(DateTime date, int durationMinutes = 30)
    {
        var dayStart = date.Date.AddHours(8);   // clinic opens 8 AM
        var dayEnd = date.Date.AddHours(18);     // clinic closes 6 PM

        var existing = await db.Appointments
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd
                     && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        var slots = new List<TimeSlot>();
        var current = dayStart;

        while (current.AddMinutes(durationMinutes) <= dayEnd)
        {
            var slotEnd = current.AddMinutes(durationMinutes);
            var isAvailable = !existing.Any(e =>
                e.StartTime < slotEnd && e.EndTime > current);

            slots.Add(new TimeSlot(current, slotEnd, isAvailable));
            current = current.AddMinutes(30); // 30-min increments
        }

        return slots;
    }

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        appointment.CreatedAt = DateTime.UtcNow;
        appointment.Status = AppointmentStatus.Scheduled;
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task<Appointment> RescheduleAsync(int id, DateTime newStartTime)
    {
        var appointment = await db.Appointments.FindAsync(id)
            ?? throw new InvalidOperationException("Appointment not found");
        appointment.StartTime = newStartTime;
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task CancelAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id)
            ?? throw new InvalidOperationException("Appointment not found");
        appointment.Status = AppointmentStatus.Cancelled;
        await db.SaveChangesAsync();
    }

    public async Task CompleteAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id)
            ?? throw new InvalidOperationException("Appointment not found");
        appointment.Status = AppointmentStatus.Completed;
        await db.SaveChangesAsync();
    }

    public async Task<Appointment> UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }
}

public record TimeSlot(DateTime Start, DateTime End, bool IsAvailable);

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(string? search = null, InvoiceStatus? status = null)
    {
        var q = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (status.HasValue)
            q = q.Where(i => i.Status == status.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.Trim().ToLower();
            q = q.Where(i => i.Pet.Name.ToLower().Contains(search)
                          || i.Pet.Owner.LastName.ToLower().Contains(search));
        }

        return await q.OrderByDescending(i => i.InvoiceDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.CreatedAt = DateTime.UtcNow;
        invoice.InvoiceDate = DateTime.UtcNow;
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Invoice> UpdateInvoiceAsync(Invoice invoice)
    {
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item is not null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.CreatedAt = DateTime.UtcNow;
        payment.PaymentDate = DateTime.UtcNow;
        db.Payments.Add(payment);

        var invoice = await db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == payment.InvoiceId);

        // Reload to get fresh totals after adding
        await db.SaveChangesAsync();

        // Check if fully paid
        await db.Entry(invoice).ReloadAsync();
        await db.Entry(invoice).Collection(i => i.Items).LoadAsync();
        await db.Entry(invoice).Collection(i => i.Payments).LoadAsync();

        if (invoice.BalanceDue <= 0)
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var q = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (invoiceId.HasValue)
            q = q.Where(p => p.InvoiceId == invoiceId.Value);

        return await q.OrderByDescending(p => p.PaymentDate).ToListAsync();
    }

    public async Task CancelInvoiceAsync(int id)
    {
        var invoice = await db.Invoices.FindAsync(id)
            ?? throw new InvalidOperationException("Invoice not found");
        invoice.Status = InvoiceStatus.Cancelled;
        await db.SaveChangesAsync();
    }
}

