using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(string? search = null, InvoiceStatus? status = null)
    {
        var q = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (status.HasValue)
            q = q.Where(i => i.Status == status.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.Trim().ToLower();
            q = q.Where(i => i.Pet.Name.ToLower().Contains(search)
                          || i.Pet.Owner.LastName.ToLower().Contains(search));
        }

        return await q.OrderByDescending(i => i.InvoiceDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.CreatedAt = DateTime.UtcNow;
        invoice.InvoiceDate = DateTime.UtcNow;
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Invoice> UpdateInvoiceAsync(Invoice invoice)
    {
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item is not null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.CreatedAt = DateTime.UtcNow;
        payment.PaymentDate = DateTime.UtcNow;
        db.Payments.Add(payment);

        var invoice = await db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == payment.InvoiceId);

        // Reload to get fresh totals after adding
        await db.SaveChangesAsync();

        // Check if fully paid
        await db.Entry(invoice).ReloadAsync();
        await db.Entry(invoice).Collection(i => i.Items).LoadAsync();
        await db.Entry(invoice).Collection(i => i.Payments).LoadAsync();

        if (invoice.BalanceDue <= 0)
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var q = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (invoiceId.HasValue)
            q = q.Where(p => p.InvoiceId == invoiceId.Value);

        return await q.OrderByDescending(p => p.PaymentDate).ToListAsync();
    }

