arguments.file_text:
@page "/"
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService AppointmentSvc
@inject PatientService PatientSvc
@inject BillingService BillingSvc

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>🏥 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="/appointments" class="btn btn-light btn-sm">View Calendar</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="/billing" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <div class="card">
            <div class="card-header"><strong>Today's Schedule</strong></div>
            <div class="card-body">
                @if (todayAppts?.Count > 0)
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Time</th><th>Patient</th><th>Reason</th><th>Status</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var a in todayAppts)
                            {
                                <tr>
                                    <td>@a.StartTime.ToString("h:mm tt")</td>
                                    <td>@a.Pet.Name (@a.Pet.Owner.LastName)</td>
                                    <td>@a.Reason</td>
                                    <td>
                                        <span class="badge bg-@GetStatusColor(a.Status)">@a.Status</span>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No appointments scheduled for today.</p>
                }
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-header"><strong>Recent Invoices</strong></div>
            <div class="card-body">
                @if (recentInvoices?.Count > 0)
                {
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Status</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var inv in recentInvoices.Take(5))
                            {
                                <tr>
                                    <td><a href="/billing/invoice/@inv.Id">INV-@inv.Id.ToString("D5")</a></td>
                                    <td>@inv.Pet.Name</td>
                                    <td>@inv.TotalAmount.ToString("C")</td>
                                    <td>
                                        <span class="badge bg-@GetInvoiceStatusColor(inv.Status)">@inv.Status</span>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                }
                else
                {
                    <p class="text-muted">No recent invoices.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private int petCount, todayAppointments, pendingInvoices, ownerCount;
    private List<VetClinic.Data.Models.Appointment>? todayAppts;
    private List<VetClinic.Data.Models.Invoice>? recentInvoices;

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);

        var pets = await PatientSvc.GetPetsAsync();
        petCount = pets.Count;

        var owners = await PatientSvc.GetOwnersAsync();
        ownerCount = owners.Count;

        todayAppts = await AppointmentSvc.GetAppointmentsAsync(today, tomorrow);
        todayAppointments = todayAppts.Count(a => a.Status != VetClinic.Data.Models.AppointmentStatus.Cancelled);

        var invoices = await BillingSvc.GetInvoicesAsync(status: VetClinic.Data.Models.InvoiceStatus.Pending);
        pendingInvoices = invoices.Count;

        recentInvoices = await BillingSvc.GetInvoicesAsync();
    }

    private string GetStatusColor(VetClinic.Data.Models.AppointmentStatus status) => status switch
    {
        VetClinic.Data.Models.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.Models.AppointmentStatus.Completed => "success",
        VetClinic.Data.Models.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };

    private string GetInvoiceStatusColor(VetClinic.Data.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Data.Models.InvoiceStatus.Pending => "warning",
        VetClinic.Data.Models.InvoiceStatus.Paid => "success",
        VetClinic.Data.Models.InvoiceStatus.Overdue => "danger",
        VetClinic.Data.Models.InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<h1>🐾 Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Search by pet name or owner..."
                   @bind="searchTerm" @bind:event="oninput" @onkeyup="SearchAsync" />
            <button class="btn btn-outline-secondary" @onclick="SearchAsync">Search</button>
        </div>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-success me-2" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-primary" @onclick="ShowAddPet">+ New Patient</button>
    </div>
</div>

@if (pets is null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pet in pets)
            {
                <tr>
                    <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                    <td>@pet.Species</td>
                    <td>@(pet.Breed ?? "—")</td>
                    <td>@pet.Owner.FullName</td>
                    <td>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@* ── Owner Modal ── *@
@if (showOwnerModal)
{
    <div class="modal show d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
                    <button type="button" class="btn-close" @onclick="() => showOwnerModal = false"></button>
                </div>
                <EditForm Model="editingOwner" OnValidSubmit="SaveOwnerAsync" FormName="ownerForm">
                    <DataAnnotationsValidator />
                    <div class="modal-body">
                        <div class="mb-3">
                            <label class="form-label">First Name</label>
                            <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                            <ValidationMessage For="() => editingOwner.FirstName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Last Name</label>
                            <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                            <ValidationMessage For="() => editingOwner.LastName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Phone</label>
                            <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                            <ValidationMessage For="() => editingOwner.Phone" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Email</label>
                            <InputText class="form-control" @bind-Value="editingOwner.Email" />
                            <ValidationMessage For="() => editingOwner.Email" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Address</label>
                            <InputTextArea class="form-control" @bind-Value="editingOwner.Address" />
                        </div>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="() => showOwnerModal = false">Cancel</button>
                        <button type="submit" class="btn btn-primary">Save</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>
}

@* ── Pet Modal ── *@
@if (showPetModal)
{
    <div class="modal show d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">@(editingPet.Id == 0 ? "Register New Patient" : "Edit Patient")</h5>
                    <button type="button" class="btn-close" @onclick="() => showPetModal = false"></button>
                </div>
                <EditForm Model="editingPet" OnValidSubmit="SavePetAsync" FormName="petForm">
                    <DataAnnotationsValidator />
                    <div class="modal-body">
                        <div class="mb-3">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-control" @bind-Value="editingPet.OwnerId">
                                <option value="0">-- Select Owner --</option>
                                @if (owners is not null)
                                {
                                    @foreach (var o in owners)
                                    {
                                        <option value="@o.Id">@o.FullName</option>
                                    }
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Name</label>
                            <InputText class="form-control" @bind-Value="editingPet.Name" />
                            <ValidationMessage For="() => editingPet.Name" />
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Species</label>
                                <InputSelect class="form-control" @bind-Value="editingPet.Species">
                                    <option value="">-- Select --</option>
                                    <option value="Dog">Dog</option>
                                    <option value="Cat">Cat</option>
                                    <option value="Bird">Bird</option>
                                    <option value="Rabbit">Rabbit</option>
                                    <option value="Reptile">Reptile</option>
                                    <option value="Other">Other</option>
                                </InputSelect>
                                <ValidationMessage For="() => editingPet.Species" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="editingPet.Breed" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-4 mb-3">
                                <label class="form-label">Date of Birth</label>
                                <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                            </div>
                            <div class="col-md-4 mb-3">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                            </div>
                            <div class="col-md-4 mb-3">
                                <label class="form-label">Sex</label>
                                <InputSelect class="form-control" @bind-Value="editingPet.Sex">
                                    <option value="">-- Select --</option>
                                    <option value="Male">Male</option>
                                    <option value="Female">Female</option>
                                    <option value="Neutered Male">Neutered Male</option>
                                    <option value="Spayed Female">Spayed Female</option>
                                </InputSelect>
                            </div>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Notes</label>
                            <InputTextArea class="form-control" @bind-Value="editingPet.Notes" />
                        </div>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="() => showPetModal = false">Cancel</button>
                        <button type="submit" class="btn btn-primary">Save</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>
}

@code {
    private List<VetClinic.Data.Models.Pet>? pets;
    private List<VetClinic.Data.Models.Owner>? owners;
    private string searchTerm = string.Empty;

    private bool showOwnerModal, showPetModal;
    private VetClinic.Data.Models.Owner editingOwner = new();
    private VetClinic.Data.Models.Pet editingPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        pets = await PatientSvc.GetPetsAsync(searchTerm);
        owners = await PatientSvc.GetOwnersAsync();
    }

    private async Task SearchAsync() => await LoadDataAsync();

    private void ShowAddOwner()
    {
        editingOwner = new VetClinic.Data.Models.Owner();
        showOwnerModal = true;
    }

    private void ShowAddPet()
    {
        editingPet = new VetClinic.Data.Models.Pet();
        showPetModal = true;
    }

    private void EditPet(VetClinic.Data.Models.Pet pet)
    {
        editingPet = pet;
        showPetModal = true;
    }

    private async Task SaveOwnerAsync()
    {
        await PatientSvc.SaveOwnerAsync(editingOwner);
        showOwnerModal = false;
        await LoadDataAsync();
    }

    private async Task SavePetAsync()
    {
        if (editingPet.OwnerId == 0) return;
        await PatientSvc.SavePetAsync(editingPet);
        showPetModal = false;
        await LoadDataAsync();
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc
@inject NavigationManager Nav
@inject AuthenticationStateProvider AuthState

<PageTitle>Patient Details</PageTitle>

@if (pet is null)
{
    <p>Loading...</p>
    return;
}

<h1>🐾 @pet.Name</h1>
<p class="text-muted">@pet.Species @(pet.Breed != null ? $"• {pet.Breed}" : "") • Owner: @pet.Owner.FullName</p>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "info" ? "active" : "")" @onclick='() => activeTab = "info"'>Info</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "history" ? "active" : "")" @onclick='() => activeTab = "history"'>Medical History</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "appointments" ? "active" : "")" @onclick='() => activeTab = "appointments"'>Appointments</button>
    </li>
</ul>

@if (activeTab == "info")
{
    <div class="card">
        <div class="card-body">
            <EditForm Model="pet" OnValidSubmit="SavePatientAsync" FormName="patientInfoForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="pet.Name" />
                        <ValidationMessage For="() => pet.Name" />
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-control" @bind-Value="pet.Species">
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="pet.Breed" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="pet.WeightKg" />
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Sex</label>
                        <InputSelect class="form-control" @bind-Value="pet.Sex">
                            <option value="">—</option>
                            <option value="Male">Male</option>
                            <option value="Female">Female</option>
                            <option value="Neutered Male">Neutered Male</option>
                            <option value="Spayed Female">Spayed Female</option>
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-3">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" rows="3" @bind-Value="pet.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save Changes</button>
                @if (saveMessage is not null)
                {
                    <span class="ms-3 text-success">@saveMessage</span>
                }
            </EditForm>
        </div>
    </div>
}
else if (activeTab == "history")
{
    <div class="d-flex justify-content-between mb-3">
        <h4>Treatment Notes</h4>
        <button class="btn btn-primary" @onclick="ShowAddNote">+ Add Treatment Note</button>
    </div>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="treatmentNoteForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                            <ValidationMessage For="() => editingNote.Diagnosis" />
                        </div>
                        <div class="col-md-3 mb-3">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="editingNote.Date" />
                        </div>
                    </div>
                    <div class="mb-3">
