                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Quantity</label>
                        <InputNumber class="form-control" @bind-Value="newItem.Quantity" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Unit Price</label>
                        <InputNumber class="form-control" @bind-Value="newItem.UnitPrice" />
                    </div>
                    <div class="col-md-2 mb-2 d-flex align-items-end">
                        <button type="submit" class="btn btn-primary me-2">Add</button>
                        <button type="button" class="btn btn-secondary" @onclick="() => showItemForm = false">Cancel</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@* ── Payment Summary ── *@
<div class="row">
    <div class="col-md-6">
        <div class="card mb-3">
            <div class="card-header"><strong>Payment Summary</strong></div>
            <div class="card-body">
                <table class="table table-sm mb-0">
                    <tr><td>Total</td><td class="text-end">@invoice.TotalAmount.ToString("C")</td></tr>
                    <tr><td>Paid</td><td class="text-end text-success">@invoice.AmountPaid.ToString("C")</td></tr>
                    <tr class="fw-bold">
                        <td>Balance Due</td>
                        <td class="text-end @(invoice.BalanceDue > 0 ? "text-danger" : "text-success")">
                            @invoice.BalanceDue.ToString("C")
                        </td>
                    </tr>
                </table>
            </div>
        </div>
    </div>

    @* ── Process Payment ── *@
    <div class="col-md-6">
        @if (invoice.Status != VetClinic.Data.Models.InvoiceStatus.Paid
          && invoice.Status != VetClinic.Data.Models.InvoiceStatus.Cancelled
          && invoice.TotalAmount > 0)
        {
            <div class="card mb-3 border-success">
                <div class="card-header"><strong>Process Payment</strong></div>
                <div class="card-body">
                    <EditForm Model="newPayment" OnValidSubmit="ProcessPaymentAsync" FormName="paymentForm">
                        <DataAnnotationsValidator />
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                            <ValidationMessage For="() => newPayment.Amount" />
                            <small class="text-muted">Balance: @invoice.BalanceDue.ToString("C")</small>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-control" @bind-Value="newPayment.Method">
                                @foreach (var m in Enum.GetValues<VetClinic.Data.Models.PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Notes</label>
                            <InputText class="form-control" @bind-Value="newPayment.Notes" />
                        </div>
                        <button type="submit" class="btn btn-success w-100">Process Payment</button>
                    </EditForm>
                </div>
            </div>
        }
    </div>
</div>

@* ── Payment History ── *@
@if (invoice.Payments.Count > 0)
{
    <div class="card mb-3">
        <div class="card-header"><strong>Payment History</strong></div>
        <div class="card-body p-0">
            <table class="table table-sm mb-0">
                <thead>
                    <tr><th>Date</th><th>Amount</th><th>Method</th><th>Notes</th></tr>
                </thead>
                <tbody>
                    @foreach (var p in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                    {
                        <tr>
                            <td>@p.PaymentDate.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td class="text-success fw-bold">@p.Amount.ToString("C")</td>
                            <td>@p.Method</td>
                            <td>@(p.Notes ?? "—")</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@* ── Actions ── *@
<div class="d-flex gap-2">
    <a href="/billing" class="btn btn-outline-secondary">← Back to Billing</a>
    @if (invoice.Status == VetClinic.Data.Models.InvoiceStatus.Pending)
    {
        <button class="btn btn-danger" @onclick="CancelInvoiceAsync">Cancel Invoice</button>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Data.Models.Invoice? invoice;
    private bool showItemForm;
    private VetClinic.Data.Models.InvoiceItem newItem = new();
    private VetClinic.Data.Models.Payment newPayment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoiceAsync();
    }

    private async Task LoadInvoiceAsync()
    {
        invoice = await BillingSvc.GetInvoiceAsync(Id);
        if (invoice is not null)
        {
            newPayment = new VetClinic.Data.Models.Payment
            {
                InvoiceId = invoice.Id,
                Amount = invoice.BalanceDue
            };
        }
    }

    private void ShowAddItem()
    {
        newItem = new VetClinic.Data.Models.InvoiceItem
        {
            InvoiceId = Id,
            Quantity = 1
        };
        showItemForm = true;
    }

    private async Task AddItemAsync()
    {
        newItem.InvoiceId = Id;
        await BillingSvc.AddInvoiceItemAsync(newItem);
        showItemForm = false;
        await LoadInvoiceAsync();
    }

    private async Task RemoveItemAsync(int itemId)
    {
        await BillingSvc.RemoveInvoiceItemAsync(itemId);
        await LoadInvoiceAsync();
    }

    private async Task ProcessPaymentAsync()
    {
        newPayment.InvoiceId = Id;
        await BillingSvc.ProcessPaymentAsync(newPayment);
        await LoadInvoiceAsync();
    }

    private async Task CancelInvoiceAsync()
    {
        await BillingSvc.CancelInvoiceAsync(Id);
        await LoadInvoiceAsync();
    }

    private string GetStatusColor(VetClinic.Data.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Data.Models.InvoiceStatus.Pending => "warning",
        VetClinic.Data.Models.InvoiceStatus.Paid => "success",
        VetClinic.Data.Models.InvoiceStatus.Overdue => "danger",
        VetClinic.Data.Models.InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}

