                @if (saveMessage is not null)
                {
                    <span class="ms-3 text-success">@saveMessage</span>
                }
            </EditForm>
        </div>
    </div>
}
else if (activeTab == "history")
{
    <div class="d-flex justify-content-between mb-3">
        <h4>Treatment Notes</h4>
        <button class="btn btn-primary" @onclick="ShowAddNote">+ Add Treatment Note</button>
    </div>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="treatmentNoteForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                            <ValidationMessage For="() => editingNote.Diagnosis" />
                        </div>
                        <div class="col-md-3 mb-3">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="editingNote.Date" />
                        </div>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Treatment</label>
                        <InputTextArea class="form-control" rows="2" @bind-Value="editingNote.Treatment" />
                        <ValidationMessage For="() => editingNote.Treatment" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Medications</label>
                        <InputText class="form-control" @bind-Value="editingNote.Medications" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Additional Notes</label>
                        <InputTextArea class="form-control" rows="2" @bind-Value="editingNote.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (pet.TreatmentNotes.Count == 0)
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h6>@note.Diagnosis</h6>
                        <small class="text-muted">@note.Date.ToString("MMM dd, yyyy") — by @note.CreatedBy</small>
                    </div>
                    <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                    @if (!string.IsNullOrEmpty(note.Medications))
                    {
                        <p class="mb-1"><strong>Medications:</strong> @note.Medications</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Notes))
                    {
                        <p class="mb-0 text-muted"><em>@note.Notes</em></p>
                    }
                </div>
            </div>
        }
    }
}
else if (activeTab == "appointments")
{
    <h4>Appointment History</h4>
    @if (pet.Appointments.Count == 0)
    {
        <p class="text-muted">No appointments recorded.</p>
    }
    else
    {
        <table class="table table-sm">
            <thead>
                <tr><th>Date/Time</th><th>Reason</th><th>Duration</th><th>Status</th></tr>
            </thead>
            <tbody>
                @foreach (var a in pet.Appointments)
                {
                    <tr>
                        <td>@a.StartTime.ToString("MMM dd, yyyy h:mm tt")</td>
                        <td>@a.Reason</td>
                        <td>@a.DurationMinutes min</td>
                        <td><span class="badge bg-@GetStatusColor(a.Status)">@a.Status</span></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

<div class="mt-3">
    <a href="/patients" class="btn btn-outline-secondary">← Back to Patients</a>
</div>

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Data.Models.Pet? pet;
    private string activeTab = "info";
    private string? saveMessage;
    private bool showNoteForm;
    private VetClinic.Data.Models.TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientSvc.GetPetAsync(Id);
    }

    private async Task SavePatientAsync()
    {
        if (pet is null) return;
        await PatientSvc.SavePetAsync(pet);
        saveMessage = "✓ Saved";
