{"file_text": "@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService AppointmentSvc
@inject PatientService PatientSvc

<PageTitle>Appointments</PageTitle>

<h1>📅 Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <div class="input-group">
            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">◀</button>
            <input type="date" class="form-control" @bind="selectedDate" @bind:event="onchange" @bind:after="LoadWeekAsync" />
            <button class="btn btn-outline-secondary" @onclick="NextWeek">▶</button>
            <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
        </div>
    </div>
    <div class="col-md-8 text-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@* ── Week Calendar View ── *@
<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center @(day.Date == DateTime.Today ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-nowrap fw-bold">@(new DateTime(2000,1,1,hour,0,0).ToString("h tt"))</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotTime = weekStart.AddDays(d).AddHours(hour);
                        var appts = weekAppointments?
                            .Where(a => a.StartTime >= slotTime && a.StartTime < slotTime.AddHours(1)
                                     && a.Status != VetClinic.Data.Models.AppointmentStatus.Cancelled)
                            .ToList();
                        <td class="@(slotTime.Date == DateTime.Today ? "table-active" : "")" style="min-width:120px">
                            @if (appts?.Count > 0)
                            {
                                @foreach (var a in appts)
                                {
                                    <div class="badge bg-@GetStatusColor(a.Status) text-wrap text-start w-100 mb-1 p-1"
                                         style="cursor:pointer" @onclick="() => EditAppointment(a)">
                                        <small>@a.StartTime.ToString("h:mm") @a.Pet.Name</small>
                                    </div>
                                }
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@* ── Appointment Modal ── *@
@if (showModal)
{
    <div class="modal show d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">
                        @(editingAppointment.Id == 0 ? "New Appointment" : $"Appointment #{editingAppointment.Id}")
                    </h5>
                    <button type="button" class="btn-close" @onclick="() => showModal = false"></button>
                </div>
                <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointmentAsync" FormName="appointmentForm">
                    <DataAnnotationsValidator />
                    <div class="modal-body">
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Patient</label>
                                <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                                    <option value="0">-- Select Patient --</option>
                                    @if (allPets is not null)
                                    {
                                        @foreach (var p in allPets)
                                        {
                                            <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                                        }
                                    }
                                </InputSelect>
                            </div>
                            <div class="col-md-3 mb-3">
                                <label class="form-label">Date & Time</label>
                                <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                            </div>
                            <div class="col-md-3 mb-3">
                                <label class="form-label">Duration (min)</label>
                                <InputNumber class="form-control" @bind-Value="editingAppointment.DurationMinutes" />
                            </div>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Reason</label>
                            <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                            <ValidationMessage For="() => editingAppointment.Reason" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Notes</label>
                            <InputTextArea class="form-control" rows="2" @bind-Value="editingAppointment.Notes" />
                        </div>

                        @* ── Available Slots ── *@
                        @if (editingAppointment.Id == 0 || isRescheduling)
                        {
                            <div class="mb-3">
                                <label class="form-label">Available Slots for @editingAppointment.StartTime.ToString("MMM dd")</label>
                                <button type="button" class="btn btn-sm btn-outline-info ms-2" @onclick="LoadSlotsAsync">Refresh Availability</button>
                                <div class="d-flex flex-wrap gap-1 mt-2">
                                    @if (availableSlots is not null)
                                    {
                                        @foreach (var slot in availableSlots)
                                        {
                                            <button type="button"
                                                    class="btn btn-sm @(slot.IsAvailable ? "btn-outline-success" : "btn-outline-secondary")"
                                                    disabled="@(!slot.IsAvailable)"
                                                    @onclick="() => SelectSlot(slot)">
                                                @slot.Start.ToString("h:mm tt")
                                            </button>
                                        }
                                    }
                                </div>
                            </div>
                        }

                        @if (editingAppointment.Id != 0)
                        {
                            <div class="mb-3">
                                <label class="form-label">Status</label>
                                <div class="btn-group">
                                    <button type="button" class="btn btn-sm btn-outline-primary @(editingAppointment.Status == VetClinic.Data.Models.AppointmentStatus.Scheduled ? "active" : "")"
                                            @onclick="() => editingAppointment.Status = VetClinic.Data.Models.AppointmentStatus.Scheduled">Scheduled</button>
                                    <button type="button" class="btn btn-sm btn-outline-success @(editingAppointment.Status == VetClinic.Data.Models.AppointmentStatus.Completed ? "active" : "")"
                                            @onclick="() => editingAppointment.Status = VetClinic.Data.Models.AppointmentStatus.Completed">Completed</button>
                                    <button type="button" class="btn btn-sm btn-outline-secondary @(editingAppointment.Status == VetClinic.Data.Models.AppointmentStatus.Cancelled ? "active" : "")"
                                            @onclick="() => editingAppointment.Status = VetClinic.Data.Models.AppointmentStatus.Cancelled">Cancelled</button>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="modal-footer">
                        @if (editingAppointment.Id != 0)
                        {
                            <button type="button" class="btn btn-warning me-auto" @onclick="ToggleReschedule">
                                @(isRescheduling ? "Stop Rescheduling" : "Reschedule")
                            </button>
                            <button type="button" class="btn btn-danger" @onclick="CancelAppointmentAsync">Cancel Appointment</button>
                        }
                        <button type="button" class="btn btn-secondary" @onclick="() => showModal = false">Close</button>
                        <button type="submit" class="btn btn-primary">Save</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>
}

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateTime weekStart;
    private List<VetClinic.Data.Models.Appointment>? weekAppointments;
    private List<VetClinic.Data.Models.Pet>? allPets;
    private List<TimeSlot>? availableSlots;

    private bool showModal, isRescheduling;
    private VetClinic.Data.Models.Appointment editingAppointment = new();

    protected override async Task OnInitializedAsync()
    {
        allPets = await PatientSvc.GetPetsAsync();
        SetWeekStart();
        await LoadWeekAsync();
    }

    private void SetWeekStart()
    {
        var diff = (int)selectedDate.DayOfWeek - (int)DayOfWeek.Monday;
        if (diff < 0) diff += 7;
        weekStart = selectedDate.AddDays(-diff).Date;
    }

    private async Task LoadWeekAsync()
    {
        SetWeekStart();
        weekAppointments = await AppointmentSvc.GetAppointmentsAsync(weekStart, weekStart.AddDays(7));
    }

    private async Task PreviousWeek() { selectedDate = selectedDate.AddDays(-7); await LoadWeekAsync(); }
    private async Task NextWeek() { selectedDate = selectedDate.AddDays(7); await LoadWeekAsync(); }
    private async Task GoToToday() { selectedDate = DateTime.Today; await LoadWeekAsync(); }

    private async void ShowNewAppointment()
    {
        editingAppointment = new VetClinic.Data.Models.Appointment
        {
            StartTime = selectedDate.Date.AddHours(9),
            DurationMinutes = 30
        };
        isRescheduling = false;
        availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(editingAppointment.StartTime.Date);
        showModal = true;
        StateHasChanged();
    }

    private async void EditAppointment(VetClinic.Data.Models.Appointment appt)
    {
        editingAppointment = appt;
        isRescheduling = false;
        availableSlots = null;
        showModal = true;
        StateHasChanged();
    }

    private async Task LoadSlotsAsync()
    {
        availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
            editingAppointment.StartTime.Date, editingAppointment.DurationMinutes);
    }

    private void SelectSlot(TimeSlot slot)
    {
        editingAppointment.StartTime = slot.Start;
    }

    private void ToggleReschedule()
    {
        isRescheduling = !isRescheduling;
        if (isRescheduling) _ = LoadSlotsAsync();
    }

    private async Task SaveAppointmentAsync()
    {
        if (editingAppointment.PetId == 0) return;
        if (editingAppointment.Id == 0)
            await AppointmentSvc.CreateAppointmentAsync(editingAppointment);
        else
            await AppointmentSvc.UpdateAppointmentAsync(editingAppointment);

        showModal = false;
        await LoadWeekAsync();
    }

    private async Task CancelAppointmentAsync()
    {
        await AppointmentSvc.CancelAsync(editingAppointment.Id);
        showModal = false;
        await LoadWeekAsync();
    }

    private string GetStatusColor(VetClinic.Data.Models.AppointmentStatus status) => status switch
    {
        VetClinic.Data.Models.AppointmentStatus.Scheduled => "primary",
        VetClinic.Data.Models.AppointmentStatus.Completed => "success",
        VetClinic.Data.Models.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}
