{"file_text": "@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingSvc
@inject PatientService PatientSvc

<PageTitle>Billing</PageTitle>

<h1>💰 Billing</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => { activeTab = "payments"; LoadPaymentsAsync(); }'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="row mb-3">
        <div class="col-md-4">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Search by pet or owner..."
                       @bind="searchTerm" @bind:event="oninput" @onkeyup="SearchAsync" />
                <button class="btn btn-outline-secondary" @onclick="SearchAsync">Search</button>
            </div>
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="statusFilter" @bind:after="SearchAsync">
                <option value="">All Statuses</option>
                @foreach (var s in Enum.GetValues<VetClinic.Data.Models.InvoiceStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
        <div class="col-md-4 text-end">
            <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
        </div>
    </div>

    @if (invoices is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Invoice #</th><th>Date</th><th>Patient</th><th>Owner</th>
                    <th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var inv in invoices)
                {
                    <tr>
                        <td><a href="/billing/invoice/@inv.Id">INV-@inv.Id.ToString("D5")</a></td>
                        <td>@inv.InvoiceDate.ToString("MM/dd/yyyy")</td>
                        <td>@inv.Pet.Name</td>
                        <td>@inv.Pet.Owner.FullName</td>
                        <td>@inv.TotalAmount.ToString("C")</td>
                        <td>@inv.AmountPaid.ToString("C")</td>
                        <td class="@(inv.BalanceDue > 0 ? "text-danger fw-bold" : "text-success")">
                            @inv.BalanceDue.ToString("C")
                        </td>
                        <td><span class="badge bg-@GetStatusColor(inv.Status)">@inv.Status</span></td>
                        <td>
                            <a href="/billing/invoice/@inv.Id" class="btn btn-sm btn-outline-primary">View</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
}
else if (activeTab == "payments")
{
    <h4>Payment History</h4>
    @if (payments is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th><th>Notes</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var p in payments)
                {
                    <tr>
                        <td>@p.PaymentDate.ToString("MM/dd/yyyy h:mm tt")</td>
                        <td><a href="/billing/invoice/@p.InvoiceId">INV-@p.InvoiceId.ToString("D5")</a></td>
                        <td>@p.Invoice.Pet.Name (@p.Invoice.Pet.Owner.LastName)</td>
                        <td class="text-success fw-bold">@p.Amount.ToString("C")</td>
                        <td>@p.Method</td>
                        <td>@(p.Notes ?? "—")</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@* ── New Invoice Modal ── *@
@if (showNewInvoiceModal)
{
    <div class="modal show d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Create New Invoice</h5>
                    <button type="button" class="btn-close" @onclick="() => showNewInvoiceModal = false"></button>
                </div>
                <EditForm Model="newInvoice" OnValidSubmit="CreateInvoiceAsync" FormName="newInvoiceForm">
                    <div class="modal-body">
                        <div class="mb-3">
                            <label class="form-label">Patient</label>
                            <InputSelect class="form-control" @bind-Value="newInvoice.PetId">
                                <option value="0">-- Select Patient --</option>
                                @if (allPets is not null)
                                {
                                    @foreach (var p in allPets)
                                    {
                                        <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                                    }
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Due Date</label>
                            <InputDate class="form-control" @bind-Value="newInvoice.DueDate" />
                        </div>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="() => showNewInvoiceModal = false">Cancel</button>
                        <button type="submit" class="btn btn-primary">Create & Add Items</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;

    private List<VetClinic.Data.Models.Invoice>? invoices;
    private List<VetClinic.Data.Models.Payment>? payments;
    private List<VetClinic.Data.Models.Pet>? allPets;

    private bool showNewInvoiceModal;
    private VetClinic.Data.Models.Invoice newInvoice = new();

    protected override async Task OnInitializedAsync()
    {
        allPets = await PatientSvc.GetPetsAsync();
        await SearchAsync();
    }

    private async Task SearchAsync()
    {
        VetClinic.Data.Models.InvoiceStatus? status = null;
        if (Enum.TryParse<VetClinic.Data.Models.InvoiceStatus>(statusFilter, out var parsed))
            status = parsed;

        invoices = await BillingSvc.GetInvoicesAsync(searchTerm, status);
    }

    private async Task LoadPaymentsAsync()
    {
        payments = await BillingSvc.GetPaymentHistoryAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoice = new VetClinic.Data.Models.Invoice
        {
            DueDate = DateTime.UtcNow.AddDays(30)
        };
        showNewInvoiceModal = true;
    }

    private async Task CreateInvoiceAsync()
    {
        if (newInvoice.PetId == 0) return;
        var created = await BillingSvc.CreateInvoiceAsync(newInvoice);
        showNewInvoiceModal = false;
        Nav.NavigateTo($"/billing/invoice/{created.Id}");
    }

    [Inject] private NavigationManager Nav { get; set; } = null!;

    private string GetStatusColor(VetClinic.Data.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Data.Models.InvoiceStatus.Pending => "warning",
        VetClinic.Data.Models.InvoiceStatus.Paid => "success",
        VetClinic.Data.Models.InvoiceStatus.Overdue => "danger",
        VetClinic.Data.Models.InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}
