        invoices = await BillingSvc.GetInvoicesAsync(searchTerm, status);
    }

    private async Task LoadPaymentsAsync()
    {
        payments = await BillingSvc.GetPaymentHistoryAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoice = new VetClinic.Data.Models.Invoice
        {
